var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"침식체 주제에...... 통신을 방해했던 거냐?","JPN":"侵食体のくせに……通信を妨害してたのか？","ENG":"You're nothing but a dirty C.O... but you managed to jam my signals?","TWN":"區區侵蝕體……竟妨礙了通信？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"네 입으로 직접 말하지 않았느냐. 이런 곳에서 구조를 바란다는 것이 얼마나 어리석은지 말이다.","JPN":"貴様は自分の口で言ったはずだ。このような場所で救助を望むのが、いかに愚かなことなのか。","ENG":"You said so yourself, have you not? You acknowledged what a foolish endeavor it is to hope for rescue from an abyss such as this.","TWN":"你剛剛不是親口說了嗎。在這種地方，期望救援是多麼愚蠢的行為。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"시련은 막바지에 이르렀다. 미물이여.","JPN":"試練は終盤を迎えた、微物よ。","ENG":"Your trial nears its end. Mortal.","TWN":"考驗已經到了最後關頭，微不足道的廢物。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"이제 얌전히 결말을 받아들여라.","JPN":"従順に結末を受け入れるのだ。","ENG":"Now acquiesce to the inevitability of its conclusion.","TWN":"現在乖乖接受你的結局吧。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......시련이라고?","JPN":"……試練だと？","ENG":"My trial?","TWN":"……考驗？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"침식체들이 갑자기 몰려든 것도, 전부 네 짓이었나?","JPN":"侵食体が突然押し寄せてきたのも、全部お前の仕業だったのか？","ENG":"Were you the one who drove all these C.O.s here?","TWN":"侵蝕體突然大量湧來，全都是你做的？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"그렇다. 준비한 것에 비하면 보잘 것 없는 규모였지.","JPN":"左様。本来用意したのものに比べると取るに足らない規模ではあったが。","ENG":"Aye. It was but a paltry detachment of a much grander force I've prepared.","TWN":"是。與準備的東西相比，規模微不足道。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"하지만 그로 인해 너희가 발악하는 모습은 훌륭한 구경거리였다.","JPN":"しかし貴様らがもがく姿は素晴らしい見世物だった。","ENG":"Even so, your desperate tantrum proved to be outstanding entertainment.","TWN":"但你們因此拼命掙扎的樣子真的很精彩。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"왕께서도 흡족해하실 만큼.","JPN":"王も満足されるほどに。","ENG":"Even the queen was pleased.","TWN":"王也很滿足。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"닥쳐......!","JPN":"黙れ！！","ENG":"Shut up!","TWN":"閉嘴……！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"카운터 워치의 힘도 잃은 주제에 입만 살았구나.","JPN":"カウンターウォッチの力も失った分際で、まだ威勢を張れるようだな。","ENG":"Your words remain undaunted, even without the power of your Counter Watch.","TWN":"都失去了制裁者能量環的力量，還這麼嘴硬。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"그렇게 분하다면 네 알량한 재주로 그 아이를 지켜 보아라.","JPN":"そんなに悔しいのであれば、その微々たる力であの娘を守ってみるがいい。","ENG":"See if your parlor tricks can save the child now.","TWN":"如果你這麼憤怒，就用用你那些微不足道的本事保護那個孩子吧。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"네가 저 아이를 구할 수 없다는 사실은 처음부터 자명했도다.","JPN":"貴様にあの娘が救えないという事実は最初からわかりきっていたことだった。","ENG":"It was always evident that you could not save the child.","TWN":"你救不了那個孩子的事實從一開始就註定了。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"결국 지금처럼 사지에 내몰리게 되리라는 것 역시.","JPN":"結局、今のように死地に追い込まれるということも。","ENG":"Just as it was clear that you would drive yourselves to the brink of destruction as you are now.","TWN":"最終還是會像現在一樣被逼入絕境。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"대체...... 우리한테 이러는 목적이 뭐냐? 저 꼬맹이를 가지고 뭘 어쩌려고?","JPN":"一体……私たちにこんなことをする目的は何だ？　あの子で何をどうするつもりだ？","ENG":"Why... Why the hell are you doing this to us? What do you plan to do with the kid?","TWN":"到底……為什麼這麼對我們？帶走那個孩子又能怎樣？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"방랑자가 앗아간 우리의 <color=#ffd34c>자매</color>를 재조립하는 데 쓰일 것이다.","JPN":"放浪者に奪われた我々の<color=#ffd34c>姉妹</color>を組み直すために使われるだろう。","ENG":"She shall be reassembled to replace our <color=#ffd34c>sister</color> whom the Wayfarer has taken from us.","TWN":"重新組裝被流浪者奪去的…我們的<color=#ffd34c>姐妹</color>。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"주인님의 뜻에 충실히 따를 자매를.","JPN":"主の意に忠実に従う姉妹を。","ENG":"The sister to faithfully obey the master's will.","TWN":"忠於主人命令的姐妹。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};